import { DataViewerModal } from './components/DataViewerModal';
import { COLORS, HANDLE_COLORS, DOOR_SPEC_MASTER, getFrameType, HINGED_HANDLES, SLIDING_HANDLES, DOOR_POINTS, getStoragePoints, getBaseboardPoints } from './constants';
import { supabase } from './supabase';

const SIMPLE_HANDLE_OPTIONS = ["セラミックホワイト", "マットブラック", "サテンニッケル"];
const PB_OPTIONS = ["9.5", "12.5", "15.0"];

const generateId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return Math.random().toString(36).substring(2) + Date.now().toString(36);
};

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [priceList, setPriceList] = useState<PriceRecord[]>([]);
  const [storageTypes, setStorageTypes] = useState<StorageTypeRecord[]>([]);
  const [shippingFees, setShippingFees] = useState<ShippingFeeRecord[]>([]);

  const [isModalOpen, setIsModalOpen] = useState(true);
  const [isInfoModalOpen, setIsInfoModalOpen] = useState(false);
  const [isWakuModalOpen, setIsWakuModalOpen] = useState(false);
  const [isHabakiModalOpen, setIsHabakiModalOpen] = useState(false);
  const [isCornerHabakiModalOpen, setIsCornerHabakiModalOpen] = useState(false);
  const [isHandleModalOpen, setIsHandleModalOpen] = useState(false);
  const [isHardwareModalOpen, setIsHardwareModalOpen] = useState(false);
  const [isColorModalOpen, setIsColorModalOpen] = useState(false);
  const [isEstimateModalOpen, setIsEstimateModalOpen] = useState(false);
  const [isOrderFlowModalOpen, setIsOrderFlowModalOpen] = useState(false);
  const [isMailModalOpen, setIsMailModalOpen] = useState(false);
  const [isEstimateSaved, setIsEstimateSaved] = useState(false);
  const [isPbModalOpen, setIsPbModalOpen] = useState(false);
  const [isDataViewerOpen, setIsDataViewerOpen] = useState(false);

  const [isStorageGuideOpen, setIsStorageGuideOpen] = useState(true);
  const [isBaseboardGuideOpen, setIsBaseboardGuideOpen] = useState(true);

  const [isValidationModalOpen, setIsValidationModalOpen] = useState(false);
  const [validationData, setValidationData] = useState<{
    errors: string[],
    warnings: string[]
  }>({ errors: [], warnings: [] });

  const [initialSettings, setInitialSettings] = useState({
    company: '',
    siteName: '',
    contactName: '',
    phone: '',
    defaultHeight: 'H2200',
    defaultDoorColor: COLORS[0],
    defaultHandleColor: SIMPLE_HANDLE_OPTIONS[0],
    defaultBaseboardColor: COLORS[0],
  });

  const [order, setOrder] = useState<OrderState>({
    customerInfo: {
      company: '',
      prefecture: '',
      streetAddress: '',
      address: '',
      siteName: '',
      contactName: '',
      phone: '',
      deliveryDate1: '',
      deliveryDate2: '',
      delivery1Selection: { baseboard: false, storage: false },
      delivery2Selection: { baseboard: false, storage: false },
      ceilingPB: '12.5',
    },
    doors: [],
    storage: {
      type: 'NONE',
      size: 'なし',
      color: COLORS[0],
      basePrice: 0,
      baseRing: 'なし',
      baseRingPrice: 0,
      filler: 'なし',
      fillerPrice: 0,
      fillerCount: 0,
      mirror: 'なし',
      mirrorPrice: 0,
    },
    baseboards: [
      { product: 'スリム巾木(t5.5×H23×L3960)', color: COLORS[0], unitPrice: 900, quantity: 0, unit: '本' },
      { product: 'スリムコーナー巾木', color: COLORS[0], unitPrice: 500, quantity: 0, unit: '個' },
    ],
    shipping: 0,
    memo: '',
  });

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const { data: doorsData, error: doorsError } = await supabase.from('internal_doors').select('*');
        if (doorsError) throw doorsError;
        const mappedDoors: PriceRecord[] = (doorsData || []).map(d => ({
          id: d.id,
          type: d.type,
          location: d.location,
          design: d.design,
          notes: '',
          height: d.height,
          framePrice: d.frame_price,
          doorPrice: d.door_price,
          setPrice: d.set_price,
          imageUrl: d.image_url
        }));
        setPriceList(mappedDoors);

        const { data: storageData, error: storageError } = await supabase.from('entrance_storages').select('*');
        if (storageError) throw storageError;
        const mappedStorage: StorageTypeRecord[] = (storageData || []).map(s => ({
          id: s.id,
          name: s.name,
          category: s.category,
          width: s.width,
          price: s.price,
          imageUrl: s.image_url
        }));
        if (!mappedStorage.find(s => s.id === 'NONE')) {
          mappedStorage.unshift({ id: "NONE", name: "なし", category: "なし", width: 0, price: 0 });
        }
        setStorageTypes(mappedStorage);

        const { data: shippingData, error: shippingError } = await supabase.from('shipping_fees').select('*').order('id');
        if (shippingError) throw shippingError;
        setShippingFees(shippingData as ShippingFeeRecord[]);

      } catch (error) {
        console.error('Error fetching data:', error);
        alert('データの取得に失敗しました。');
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  useEffect(() => {
    if (shippingFees.length === 0) return;
    const address = order.customerInfo.address;
    let matchedFee = 0;
    let longestMatch = -1;

    shippingFees.forEach(fee => {
        if (address.includes(fee.prefecture)) {
            if (fee.prefecture.length > longestMatch) {
                longestMatch = fee.prefecture.length;
                matchedFee = fee.price;
            }
        }
    });

    setOrder(prev => {
        if (prev.shipping === matchedFee) return prev;
        return { ...prev, shipping: matchedFee };
    });
  }, [shippingFees, order.customerInfo.address]);

  const resolveHandleName = (simpleName: string, doorType: string) => {
    if (doorType.includes("折戸") || doorType.includes("物入")) return "J型取手";
    const isSliding = doorType.includes("引") || doorType.includes("引き");
    const list = isSliding ? SLIDING_HANDLES : HINGED_HANDLES;
    return list.find(h => h.includes(simpleName)) || list[0];
  };

  const handleStart = () => {
    const defaultType = DoorType.Hinged;
    const defaultSpec = DOOR_SPEC_MASTER[defaultType];
    const defaultDesign = defaultSpec.designs[0]; 
    const initialPrice = priceList.find(p => p.type === defaultType && p.height === initialSettings.defaultHeight && p.design === defaultDesign)?.setPrice || 27300;

    setOrder(prev => ({
      ...prev,
      customerInfo: { 
        ...prev.customerInfo, 
        company: initialSettings.company, 
        siteName: initialSettings.siteName, 
        contactName: initialSettings.contactName,
        phone: initialSettings.phone
      },
      storage: { ...prev.storage, color: initialSettings.defaultDoorColor },
      baseboards: prev.baseboards.map(b => ({ ...b, color: initialSettings.defaultBaseboardColor })),
      doors: [{
        id: generateId(),
        roomName: 'LDK',
        type: defaultType,
        design: defaultDesign,
        width: '778',
        height: initialSettings.defaultHeight,
        frameType: getFrameType(defaultType, initialSettings.defaultHeight),
        hangingSide: '右吊元(R)',
        doorColor: initialSettings.defaultDoorColor,
        frameColor: initialSettings.defaultDoorColor,
        handleColor: resolveHandleName(initialSettings.defaultHandleColor, defaultType),
        specialNotes: '',
        price: initialPrice,
        isUndercut: false,
        undercutHeight: 120,
        isFrameExtended: false,
        frameExtensionHeight: 130,
      }]
    }));
    setIsModalOpen(false);
  };

  const addDoorRow = () => {
    const defaultType = DoorType.Hinged;
    const defaultSpec = DOOR_SPEC_MASTER[defaultType];
    const defaultDesign = defaultSpec.designs[0];
    const initialPrice = priceList.find(p => p.type === defaultType && p.height === initialSettings.defaultHeight && p.design === defaultDesign)?.setPrice || 27300;

    setOrder(prev => ({
      ...prev,
      doors: [...prev.doors, {
        id: generateId(),
        roomName: '',
        type: defaultType,
        design: defaultDesign,
        width: '778', 
        height: initialSettings.defaultHeight,
        frameType: getFrameType(defaultType, initialSettings.defaultHeight),
        hangingSide: 'なし',
        doorColor: initialSettings.defaultDoorColor,
        frameColor: initialSettings.defaultDoorColor,
        handleColor: resolveHandleName(initialSettings.defaultHandleColor, defaultType),
        specialNotes: '',
        price: initialPrice,
        isUndercut: false,
        undercutHeight: 120,
        isFrameExtended: false,
        frameExtensionHeight: 130,
      }]
    }));
  };

  const updateDoor = useCallback((id: string, updates: Partial<DoorItem>) => {
    setOrder(prev => ({ ...prev, doors: prev.doors.map(d => d.id === id ? { ...d, ...updates } : d) }));
  }, []);

  const removeDoor = useCallback((id: string) => {
    if (window.confirm('このWD行を削除してもよろしいですか？')) {
      setOrder(prev => ({ ...prev, doors: prev.doors.filter(d => d.id !== id) }));
    }
  }, []);

  const handlePrefectureChange = (prefecture: string) => {
    setOrder(prev => {
      const newPrefecture = prefecture;
      const combinedAddress = `${newPrefecture}${prev.customerInfo.streetAddress}`;
      return {
        ...prev,
        customerInfo: {
          ...prev.customerInfo,
          prefecture: newPrefecture,
          address: combinedAddress
        }
      };
    });
  };

  const handleStreetAddressChange = (street: string) => {
    setOrder(prev => {
      const combinedAddress = `${prev.customerInfo.prefecture}${street}`;
      return {
        ...prev,
        customerInfo: {
          ...prev.customerInfo,
          streetAddress: street,
          address: combinedAddress
        }
      };
    });
  };

  const handleUpdateShipping = (id: number, newPrice: number) => {
    setShippingFees(prev => prev.map(item => item.id === id ? { ...item, price: newPrice } : item));
  };

  const handleDeliveryItemChange = (dateNum: 1 | 2, item: 'baseboard' | 'storage', checked: boolean) => {
    setOrder(prev => {
      const newInfo = { ...prev.customerInfo };
      if (dateNum === 1) {
        newInfo.delivery1Selection = { ...newInfo.delivery1Selection, [item]: checked };
        if (checked) {
          newInfo.delivery2Selection = { ...newInfo.delivery2Selection, [item]: false };
        }
      } else {
        newInfo.delivery2Selection = { ...newInfo.delivery2Selection, [item]: checked };
        if (checked) {
          newInfo.delivery1Selection = { ...newInfo.delivery1Selection, [item]: false };
        }
      }
      return { ...prev, customerInfo: newInfo };
    });
  };

  const totals = useMemo(() => {
    const doorPoints = order.doors.reduce((sum, d) => sum + (DOOR_POINTS[d.type] || 0), 0);
    const storagePoints = getStoragePoints(order.storage.type);
    const totalBaseboardQty = order.baseboards.reduce((sum, b) => b.unit === '本' ? sum + b.quantity : sum, 0);
    const baseboardPoints = getBaseboardPoints(totalBaseboardQty);
    const totalPoints = doorPoints + storagePoints + baseboardPoints;
    const baseShipping = order.shipping;
    const finalShipping = totalPoints >= 10 ? baseShipping : Math.floor(baseShipping * (totalPoints / 10));
    const doorSubtotal = order.doors.reduce((sum, d) => sum + d.price, 0);
    const storageSubtotal = order.storage.type === 'NONE' ? 0 : order.storage.basePrice + order.storage.baseRingPrice + (order.storage.fillerPrice * order.storage.fillerCount) + order.storage.mirrorPrice;
    const baseboardSubtotal = order.baseboards.reduce((sum, b) => sum + (b.unitPrice * b.quantity), 0);
    const subtotal = doorSubtotal + storageSubtotal + baseboardSubtotal + finalShipping;
    const tax = Math.floor(subtotal * 0.1);
    const total = subtotal + tax;
    return { doorSubtotal, storageSubtotal, baseboardSubtotal, subtotal, tax, total, totalPoints, finalShipping, isShippingDiscounted: totalPoints > 0 && totalPoints < 10 };
  }, [order]);

  const hasStorage = useMemo(() => order.storage.type !== 'NONE', [order.storage.type]);
  const hasBaseboard = useMemo(() => order.baseboards.reduce((sum, b) => sum + b.quantity, 0) > 0, [order.baseboards]);
  const isStorageDateSelected = order.customerInfo.delivery1Selection.storage || order.customerInfo.delivery2Selection.storage;
  const isBaseboardDateSelected = order.customerInfo.delivery1Selection.baseboard || order.customerInfo.delivery2Selection.baseboard;
  const showStorageBubble = hasStorage && !isStorageDateSelected && isStorageGuideOpen;
  const showBaseboardBubble = hasBaseboard && !isBaseboardDateSelected && isBaseboardGuideOpen;

  const handleOpenEstimate = () => {
    const errors: string[] = [];
    const warnings: string[] = [];
    const basicFields = [
      { key: 'company', label: '会社名' },
      { key: 'siteName', label: '現場名' },
      { key: 'contactName', label: 'ご担当者名' },
      { key: 'prefecture', label: '都道府県' },
      { key: 'streetAddress', label: '以降の住所' },
    ];
    basicFields.forEach(f => { if (!order.customerInfo[f.key as keyof typeof order.customerInfo]) errors.push(`${f.label}が入力されていません。`); });
    if (!order.customerInfo.deliveryDate1 && !order.customerInfo.deliveryDate2) errors.push('納品希望日が入力されていません。');
    if (hasBaseboard && !order.customerInfo.delivery1Selection.baseboard && !order.customerInfo.delivery2Selection.baseboard) errors.push('巾木の納品希望日（①または②）が選択されていません。');
    if (hasStorage && !order.customerInfo.delivery1Selection.storage && !order.customerInfo.delivery2Selection.storage) errors.push('玄関収納の納品希望日（①または②）が選択されていません。');
    if (order.shipping === 0) errors.push('送料が計算できません。都道府県を確認してください。');
    if (order.doors.length === 0 && order.storage.type === 'NONE') errors.push('商品を選択してください。');
    if (errors.length > 0 || warnings.length > 0) {
      setValidationData({ errors, warnings });
      setIsValidationModalOpen(true);
      return;
    }
    setIsEstimateModalOpen(true);
  };

  const handleLaunchMail = () => {
    const subject = "注文書送付依頼書";
    const body = `柏木工株式会社 担当：滝下 様\nお世話になっております。\n以下の案件について、注文書の作成をお願いいたします。\n\n■お客様情報\n会社名：${order.customerInfo.company}\n担当者名：${order.customerInfo.contactName}\n現場名：${order.customerInfo.siteName}\n連絡先：${order.customerInfo.phone}\n\n■備考\n${order.memo}\n\n--- ※重要※ この後、下記3点のファイルを必ず添付して送信してください。\n1. 見積書PDF\n2. 現地案内図\n3. 平面図\n---`;
    window.location.href = `mailto:takishita@kashiwa-f.com?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    setIsMailModalOpen(false);
  };

  const handleCeilingPbChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const value = e.target.value;
    setOrder(p => ({ ...p, customerInfo: { ...p.customerInfo, ceilingPB: value } }));
    if (value === '15.0') setIsPbModalOpen(true);
  };

  const handlePrintPdf = () => { window.print(); };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-slate-100"><div className="animate-spin rounded-full h-16 w-16 border-t-4 border-b-4 border-blue-600"></div></div>;

  return (
    <div className="min-h-screen bg-slate-100 font-['Noto_Sans_JP']">
      {isDataViewerOpen && (
        <DataViewerModal onClose={() => setIsDataViewerOpen(false)} priceList={priceList} storageTypes={storageTypes} shippingFees={shippingFees} onUpdateShipping={handleUpdateShipping} setPriceList={setPriceList} setStorageTypes={setStorageTypes} />
      )}
      {isMailModalOpen && (
        <div className="fixed inset-0 z-[250] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4" onClick={() => setIsMailModalOpen(false)}>
          <div className="bg-white p-8 rounded-2xl shadow-2xl max-w-2xl w-full" onClick={(e) => e.stopPropagation()}>
            <h3 className="text-xl font-bold mb-6">メール送信の準備</h3>
            <button onClick={handleLaunchMail} disabled={!isEstimateSaved} className="w-full bg-blue-600 text-white p-3 rounded-xl font-bold disabled:bg-gray-300">メールアプリを起動</button>
          </div>
        </div>
      )}
      {isOrderFlowModalOpen && (
        <div className="fixed inset-0 z-[150] bg-gray-600/90 flex items-center justify-center p-4" onClick={() => setIsOrderFlowModalOpen(false)}>
          <div className="bg-white rounded-3xl p-10 max-w-5xl w-full" onClick={(e) => e.stopPropagation()}>
            <h3 className="text-3xl font-bold mb-6">ご注文フロー確認</h3>
            <button onClick={() => setIsOrderFlowModalOpen(false)} className="bg-gray-200 px-6 py-2 rounded-xl">閉じる</button>
          </div>
        </div>
      )}
      {isEstimateModalOpen && (
        <div className="fixed inset-0 z-[150] bg-gray-600/90 overflow-y-auto">
          <div className="bg-white max-w-[1000px] mx-auto p-10 my-10 rounded-sm shadow-2xl">
            <h2 className="text-4xl font-bold border-b-4 mb-6">御見積書</h2>
            <div className="flex justify-end gap-3 mb-10">
              <button onClick={() => setIsEstimateModalOpen(false)} className="px-6 py-2 border rounded">戻る</button>
              <button onClick={handlePrintPdf} className="px-6 py-2 bg-gray-800 text-white rounded">PDF保存</button>
            </div>
            {/* Estimate detail simplified for brevity */}
            <div className="bg-gray-100 p-6 rounded mb-10 flex justify-between">
              <span className="text-xl font-bold">御見積合計（税込）</span>
              <span className="text-2xl font-black">¥{totals.total.toLocaleString()}</span>
            </div>
          </div>
        </div>
      )}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4">
          <div className="bg-white rounded-2xl max-w-4xl w-full p-10">
            <h2 className="text-2xl font-bold mb-6">初期設定</h2>
            <div className="grid grid-cols-2 gap-6 mb-8">
              <input type="text" className="border p-3 rounded" placeholder="会社名" value={initialSettings.company} onChange={e => setInitialSettings(p => ({...p, company: e.target.value}))} />
              <input type="text" className="border p-3 rounded" placeholder="現場名" value={initialSettings.siteName} onChange={e => setInitialSettings(p => ({...p, siteName: e.target.value}))} />
            </div>
            <button onClick={handleStart} className="w-full bg-blue-600 text-white p-4 rounded-xl font-bold">入力を開始する</button>
          </div>
        </div>
      )}

      <div className={`max-w-[1550px] mx-auto p-8 bg-white shadow-xl my-8 rounded-3xl ${isModalOpen || isEstimateModalOpen || isOrderFlowModalOpen ? 'hidden' : 'block'}`}>
        <div className="flex justify-between items-center mb-8 border-b-2 pb-4">
          <h1 className="text-3xl font-black">柏木工 オリジナルドア 発注書</h1>
          <div className="flex gap-4">
            <button onClick={() => setIsOrderFlowModalOpen(true)} className="px-6 py-2 border-2 border-blue-600 text-blue-600 rounded-xl font-bold">注文フロー確認</button>
            <button onClick={handleOpenEstimate} className="px-8 py-2 bg-blue-600 text-white rounded-xl font-bold">見積書作成</button>
          </div>
        </div>

        <div className="grid grid-cols-4 gap-6 mb-8 bg-gray-50 p-6 rounded-2xl border">
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400">会社名</label>
            <input type="text" className="w-full border rounded-lg p-2.5 bg-white" value={order.customerInfo.company} onChange={e => setOrder(p => ({...p, customerInfo: {...p.customerInfo, company: e.target.value}}))} />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400">現場名</label>
            <input type="text" className="w-full border rounded-lg p-2.5 bg-white" value={order.customerInfo.siteName} onChange={e => setOrder(p => ({...p, customerInfo: {...p.customerInfo, siteName: e.target.value}}))} />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400">担当者名</label>
            <input type="text" className="w-full border rounded-lg p-2.5 bg-white" value={order.customerInfo.contactName} onChange={e => setOrder(p => ({...p, customerInfo: {...p.customerInfo, contactName: e.target.value}}))} />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400">連絡先</label>
            <input type="text" className="w-full border rounded-lg p-2.5 bg-white" value={order.customerInfo.phone} onChange={e => setOrder(p => ({...p, customerInfo: {...p.customerInfo, phone: e.target.value}}))} />
          </div>
          <div className="col-span-2 flex gap-2">
            <div className="flex-1 space-y-1">
              <label className="text-[10px] font-bold text-gray-400">都道府県 (送料算定用)</label>
              <select 
                className={`w-full border rounded-lg p-2.5 font-medium focus:ring-1 outline-none ${!order.customerInfo.prefecture ? 'border-red-300 bg-red-50' : 'bg-white'}`}
                value={order.customerInfo.prefecture}
                onChange={(e) => handlePrefectureChange(e.target.value)}
              >
                <option value="">都道府県を選択してください</option>
                {Array.from(new Set(shippingFees.map(f => f.prefecture))).map(pref => (
                  <option key={pref} value={pref}>{pref}</option>
                ))}
              </select>
            </div>
            <div className="flex-[2] space-y-1">
              <label className="text-[10px] font-bold text-gray-400">以降の住所 (市区町村・番地)</label>
              <input 
                type="text" 
                className="w-full border border-gray-200 rounded-lg p-2.5 bg-white" 
                placeholder="市区町村、番地、建物名を入力してください"
                value={order.customerInfo.streetAddress}
                onChange={(e) => handleStreetAddressChange(e.target.value)}
              />
            </div>
          </div>
          <div className="col-span-1 space-y-1">
            <label className="text-[10px] font-bold text-gray-400">納品希望日</label>
            <div className="space-y-2">
              <BusinessDatePicker value={order.customerInfo.deliveryDate1} onChange={d => setOrder(p => ({...p, customerInfo: {...p.customerInfo, deliveryDate1: d}}))} label="①枠" colorClass="bg-blue-600" />
              <BusinessDatePicker value={order.customerInfo.deliveryDate2} onChange={d => setOrder(p => ({...p, customerInfo: {...p.customerInfo, deliveryDate2: d}}))} label="②本体" colorClass="bg-green-600" />
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400">天井PB厚</label>
            <select className="w-full border rounded-lg p-2.5 bg-white" value={order.customerInfo.ceilingPB} onChange={handleCeilingPbChange}>
              {PB_OPTIONS.map(o => <option key={o} value={o}>{o}㎜</option>)}
            </select>
          </div>
        </div>

        <div className="overflow-x-auto border rounded-2xl mb-8">
          <table className="w-full text-xs text-center border-collapse">
            <thead className="bg-gray-800 text-white font-bold">
              <tr>
                <th className="p-3">No.</th>
                <th>部屋名</th>
                <th>種類</th>
                <th>デザイン</th>
                <th>幅</th>
                <th>高さ</th>
                <th>枠仕様</th>
                <th>吊元</th>
                <th>扉カラー</th>
                <th>枠カラー</th>
                <th>ハンドル</th>
                <th>価格</th>
                <th>操作</th>
              </tr>
            </thead>
            <tbody>
              {order.doors.map((door, idx) => (
                <DoorRow key={door.id} index={idx} door={door} updateDoor={updateDoor} removeDoor={removeDoor} initialSettings={initialSettings} onShowHandleImage={() => setIsHandleModalOpen(true)} siteName={order.customerInfo.siteName} priceList={priceList} />
              ))}
            </tbody>
          </table>
          <div className="p-4 bg-gray-50 flex justify-between items-center">
            <button onClick={addDoorRow} className="px-6 py-2 bg-blue-50 text-blue-600 font-bold rounded-xl border border-blue-200">建具を追加する</button>
            <div className="text-2xl font-black text-blue-700">建具合計: ¥{totals.doorSubtotal.toLocaleString()}</div>
          </div>
        </div>

        <EntranceStorageSection storage={order.storage} updateStorage={u => setOrder(p => ({...p, storage: {...p.storage, ...u}}))} siteName={order.customerInfo.siteName} storageTypes={storageTypes} />

        <div className="grid grid-cols-2 gap-8 mt-10">
          <div className="border p-6 rounded-2xl bg-white">
            <h3 className="text-xl font-bold mb-6 border-l-4 border-emerald-600 pl-3">巾木・造作材</h3>
            {order.baseboards.map((b,i) => (
              <div key={i} className="flex justify-between items-center py-4 border-b last:border-0">
                <span className="font-bold text-sm">{b.product}</span>
                <input type="number" className="w-20 border rounded text-center p-1" value={b.quantity} onChange={e => { const nb = [...order.baseboards]; nb[i].quantity = parseInt(e.target.value)||0; setOrder(p=>({...p, baseboards:nb})); }} />
              </div>
            ))}
            <div className="mt-4 text-right text-2xl font-black text-blue-700">合計: ¥{totals.baseboardSubtotal.toLocaleString()}</div>
          </div>
          <div className="bg-gray-900 text-white p-10 rounded-3xl flex flex-col justify-between">
            <div className="space-y-4">
              <div className="flex justify-between"><span>配送点数</span><span className="font-bold">{totals.totalPoints} 点</span></div>
              <div className="flex justify-between"><span>送料</span><span className="font-bold">¥{totals.finalShipping.toLocaleString()}</span></div>
              <div className="flex justify-between text-2xl font-black mt-10 border-t pt-4"><span>合計（税込）</span><span>¥{totals.total.toLocaleString()}</span></div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
